// OVER-ENGINEERED: MediatR cho CRUD đơn giản
public record GetProductQuery(int Id) : IRequest<ProductDto?>;
public class GetProductHandler(IProductRepository repo) : IRequestHandler<GetProductQuery, ProductDto?>
{
    public async Task<ProductDto?> Handle(GetProductQuery q, CancellationToken ct)
        => await repo.GetDtoAsync(q.Id, ct); // chỉ forward, không logic
}
// Controller inject IMediator, gửi GetProductQuery → handler → repo
// 3 files, 3 classes, cho 3 lines logic

// SIMPLER: Direct injection
app.MapGet("/api/products/{id:int}", async (int id, IProductRepository repo, CancellationToken ct) =>
{
    var product = await repo.GetDtoAsync(id, ct);
    return product is not null ? Results.Ok(product) : Results.NotFound();
});

// MediatR CÓ GIÁ TRỊ khi:
// 1. Pipeline behaviors: validation, logging, transaction cross-cutting
// 2. Event handlers: domain events với nhiều subscribers
// 3. Complex command/query với business logic
// 4. Large team, bounded contexts cần loose coupling

// Checklist trước khi thêm MediatR:
// ☐ Có pipeline behaviors cần thiết? (validation, transaction, logging)
// ☐ Có nhiều event handlers subscribe cùng event?
// ☐ Handlers có logic phức tạp, không chỉ forward?
// → Nếu tất cả là KHÔNG, không cần MediatR
